#include <stdio.h>
#include <time.h>

typedef struct {
    int tokens;
    int max_tokens;
    int refill_rate; // tokens per second
    time_t last_refill;
} TokenBucket;

void init_bucket(TokenBucket *bucket, int max_tokens, int rate) {
    bucket->tokens = max_tokens;
    bucket->max_tokens = max_tokens;
    bucket->refill_rate = rate;
    bucket->last_refill = time(NULL);
}

int allow_request(TokenBucket *bucket) {
    time_t now = time(NULL);
    int elapsed = now - bucket->last_refill;

    // Refill tokens based on elapsed time
    bucket->tokens += elapsed * bucket->refill_rate;
    if (bucket->tokens > bucket->max_tokens)
        bucket->tokens = bucket->max_tokens;

    bucket->last_refill = now;

    // Check if tokens available
    if (bucket->tokens >= 1) {
        bucket->tokens--;
        return 1; // Allow request
    }
    return 0; // Deny request (rate limited)
}

int main() {
    TokenBucket bucket;
    init_bucket(&bucket, 100, 10); // Max 100 tokens, 10 per sec

    // Simulate requests
    for (int i = 0; i < 150; i++) {
        if (allow_request(&bucket))
            printf("Request %d: ALLOWED\n", i+1);
        else
            printf("Request %d: BLOCKED (Rate Limited)\n", i+1);
    }
    return 0;
}
